CREATE TRIGGER [pheedloop].trgUpdateRegistrations
ON [pheedloop].[Registrations]
AFTER UPDATE
AS
BEGIN
    SET NOCOUNT ON;
    UPDATE
        [pheedloop].[Registrations]
    SET
        __mj_UpdatedAt = GETUTCDATE()
    FROM
        [pheedloop].[Registrations] AS _organicTable
    INNER JOIN
        INSERTED AS I ON
        _organicTable.[code] = I.[code];
END;
